enum NetError: Error { case failed }
func loadData() throws -> String { throw NetError.failed }

// Using 'try?' with 'if let'
if let data = try? loadData() {
    print("Success: \(data)")
} else {
    print("It failed, returning nil. Safely handled!")
}
